sql:
SELECT country_id, happiness_score 
FROM happiness_report
WHERE year = 2022;

SELECT AVG(happiness_score) AS average_happiness_score
FROM happiness_report
WHERE family_support > (
    SELECT AVG(family_support) FROM happiness_report
);

SELECT health_life_expectancy
FROM happiness_report
WHERE trust_government > 5 AND economy_gdp BETWEEN 1 AND 2 AND family_support < 1;

SELECT happiness_rank, happiness_score
FROM happiness_report
WHERE country_id = (SELECT country_id FROM countries WHERE country_name = 'Switzerland');

external_knowledge:
- "greatest happiness" refers to the lowest happiness rank;
- "golden years" refers to the period between 2019 and 2022, where the happiness rank is at its lowest (best);
- "scores" refer to the happiness scores associated with the corresponding happiness ranks.
